var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"요원에게 있어서 가장 중요한 건, 판단력이지!","JPN":"エージェントにとってもっとも大事なのは、判断力だ！","ENG":"The most important thing for an agent is judgment skills!","TWN":"對特工來說最重要的，是判斷力！"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨셨다면 어둠에 허를 찔리셨겠지만 상대가 나빴어! 애송이!","JPN":"お嬢様だったら暗闇でパニックになっていただろうが、相手を間違えたな！　小僧！","ENG":"If it were Elizabeth, your little scheme would've worked. But too bad it's me, kid!","TWN":"如果是小姐，應該會在黑暗中被擊中要害，但你的對手可是我！小鬼！"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이 늙은이에게 있어서 어둠은 그림자의 연장선……!","JPN":"この老人にとって暗闇は影の延長線……！","ENG":"Darkness is just an extension of shadows to me...!","TWN":"對於我來說，黑暗便是影子的延續……！"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"마치, 물 만난 물고기라고 해야 할까!","JPN":"まるで、水を得た魚のようだ！","ENG":"I am now in my element!","TWN":"就像，如魚得水！"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……큭!","JPN":"……くっ！","ENG":"...Krrrgh!","TWN":"……咳！"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이제 손패가 다 떨어진 것 같은데 이제 포기하는 게 어떠나, 애송이 버넷?","JPN":"もう手札がなくなったようだが、諦めたらどうだ？　バーネットの小僧。","ENG":"Seems like you ran out of clever tricks. How about you give up, kid Burnett?","TWN":"你手上好像已經沒有牌了，放棄吧，小鬼伯內特？"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐, 이번에는 꽤나 잘 해주었어. 재도전은 언제든 환영이라네.","JPN":"まあそれでも、今回はよくやった。再挑戦はいくらでも歓迎するぞ。","ENG":"But you did good this time. You're welcome to challenge me again any time.","TWN":"這次的表現還不錯，歡迎隨時再次挑戰。"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"무슨 헛소리야. 재도전 같은 건 생각하지도 않았어!","JPN":"ふざけるな。俺は今勝つことしか考えちゃいない！","ENG":"What are you talking about? I'm not challenging you twice!","TWN":"說什麼傻話呢，我可從沒想過要挑戰第二次！"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"예상하고 있었어. 어둠에 눈이 익을 때쯤 할배는 그림자 도약을 써서 공격할 거라고.","JPN":"予想どおりだ。暗闇に目が慣れたころには、ジジイは影を利用して攻撃してくるって。","ENG":"I anticipated that you'd use your shadow leap to attack when your eyes had adjusted to the darkness.","TWN":"我早就預料到，黑暗裡你會使用影子躍遷進攻。"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 그림자 도약을 쓸 때, 할배는 습관적으로 오른쪽으로 도약하지.","JPN":"そして影で移動する時、ジジイは癖で右に動く。","ENG":"And when you use your skill, you have a habit of jumping to your right.","TWN":"還有，躍遷的時候，爺爺你習慣性地往右跳躍。"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"왜냐하면 모건 할배는 왼쪽 눈이 보이지 않으니까.","JPN":"なぜなら、モーガンのジジイは左目が見えないから。","ENG":"That's because you can't see out of your left eye.","TWN":"因為摩根老頭你的左眼看不見。"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까, 타이밍은…….","JPN":"だから、タイミングは……","ENG":"So... the timing is...","TWN":"所以說，時機……"},"stage":{"bg":"BLACK","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"바로 지금!","JPN":"今だ！","ENG":"Right now!","TWN":"就是現在！"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"……흐음?","JPN":"……ほう？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"TRAINING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……으음.","JPN":"……うーん。","ENG":"...Mm.","TWN":"……呃嗯。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"홍차 폭탄……?","JPN":"紅茶爆弾……？","ENG":"Tea Bomb...?","TWN":"紅茶炸彈……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야, 네가 왜 여기 있어……? 그보다 심사는……?","JPN":"な、なんでお前がここに……？　それより審査は……？","ENG":"Huh? What are you doing here...? What happened to my test...?","TWN":"什麼啊，你怎麼在這……？對了，審核怎麼樣了……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"어이가 없군요, 물벼룩.","JPN":"呆れましたわ、ミジンコ。","ENG":"You're unbelievable, Water Flea.","TWN":"真是令人無言啊，水蚤。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"고작 심사에서 이겨보겠다고, 아티팩트 관리 시설을 건드려요?","JPN":"審査で勝つために、アーティファクト管理施設に手を出すなんて。","ENG":"You tampered with the Artifact management system just to pass a test?","TWN":"為了透過區區考核，你就對人造神器管理設施動手腳？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관원으로서 자각이 있긴 한가요? 보관 중인 아티팩트가 잘못됐으면 어쩌려고 했죠?","JPN":"機関員としての自覚はあるのですか？　保管中のアーティファクトに何かあったらどうなさるおつもりで？","ENG":"Are you even aware that you are a member of the Institution? What if something horrible had happened to the Artifacts in our possession?","TWN":"你真的有資格成為機關成員嗎？如果保管中的人造神器出現問題怎麼辦？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 아무 일 없었으면 그걸로…….","JPN":"ったく。何もなかったならそれで……","ENG":"Blimey. But nothing did happ–","TWN":"真是的，不是沒發生什麼事嗎，那就……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아야야야야야! 야, 아파! 아프다고!","JPN":"いててててて！　痛い！　痛いって！","ENG":"Owwwww! Hey! That hurts! A lot!","TWN":"哎唷喂！喂，好痛！很痛啦！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"심사는 불합격이에요. 당신 같은 무뢰한에게 요원 자격을 드릴 수 없습니다.","JPN":"審査は不合格ですわ。あなたのような乱暴者にエージェントの資格を与えるわけにはいきません。","ENG":"You failed the test. We cannot appoint someone as reckless as you as an agent.","TWN":"你的考核不合格。我不能讓你這種無賴當特工。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"더불어 정직 3개월에 감봉도 추가해 드리죠.","JPN":"それから、停職3か月に減給も追加です。","ENG":"On top of that, you are suspended for three months with a pay cut.","TWN":"同時，停職3個月，再減薪。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 결국 져버린 건가?","JPN":"ったく。結局負けたのか？","ENG":"Ugh, I lost...?","TWN":"呃，結果我還是輸了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"기껏 안 돌아가는 머리 굴려가면서 짜낸 비책이었는데, 이렇게 쉽게 막힐 줄이야.","JPN":"せっかくない頭を使って絞りだした秘策だったのに、こんな簡単に止められるなんて。","ENG":"That was all I could come up with after racking my brain... I didn't expect it to be blocked so easily.","TWN":"我好不容易動腦筋想出來的絕招，沒想到這麼容易就被看破了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"저렇게 쌩쌩한데, 무슨 은퇴를 하겠다는 거야. 망할 할배.","JPN":"あんなにピンピンしてるくせに、なにが引退だ。クソジジイ。","ENG":"That old man's still full of energy, so why's he even thinking of retiring? Stupid old chap.","TWN":"明明那麼神采奕奕，還說什麼要退休，那個死老頭。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"후후, 자네가 그렇게까지 말해준다면 은퇴는 좀 더 미뤄봐야겠는데?","JPN":"ふふ、君がそこまで言ってくれるなら、引退はもう少し考えてみるか。","ENG":"Hah hah. Hearing that makes me reconsider my retirement plans.","TWN":"呵呵，既然你都那麼說了，那我的退休還得再往後推呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"마지막에는 나도 모르게 힘이 들어가버렸어. 기절까지 시킬 생각은 없었는데 말이지.","JPN":"最後のは、思わず力が入ってしまったのだ。気絶させるつもりはなかったよ。","ENG":"I unconsciously applied too much force to the last hit at the end. I didn't mean to knock you out.","TWN":"最後一刻，不知不覺也用力了。不過還真沒想過要把你弄暈。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"첫 정식 요원 심사였는데도 무척 잘해주었네, 애송이 버넷.","JPN":"初の正式エージェント審査にしては上出来だ、バーネットの小僧。","ENG":"You did well for your first test, kid Burnett.","TWN":"雖然是第一次正式特工考核，但你做得非常好，小鬼伯內特。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러게 살살 좀 하지 그랬어.","JPN":"だから手加減しろっての。","ENG":"I told you to go easy on me.","TWN":"知道就下手輕一點啊……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어라? 얼굴에 그건 또 뭐야? 나이 먹고 안 어울리게 무슨 사자 반창고를 붙이고 있어?","JPN":"ん？　顔のそれは何だ？　その年でライオンの絆創膏か？","ENG":"Huh? What's that on your face? Why do you have a lion bandage? It doesn't suit you, old man.","TWN":"嗯？你臉上那個塊是什麼？這麼大年紀了，還貼卡通獅子圖案的OK蹦？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 안 어울리나? 이거 섭섭하군. 아가씨께서 붙여준 건데 말이야.","JPN":"はは、似合わないか？　それは残念だ。せっかくお嬢様に貼ってもらったのだがな。","ENG":"Hah hah, is that so? That's a little upsetting. The lady here is the one who gave it to me.","TWN":"哈哈，不合適嗎？有點讓人傷心呢。這可是小姐幫我貼的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"何だと？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"마지막에 자네가 휘두른 사슬에 닿아서 쓸린 상처라네.","JPN":"最後に君が振り回した鎖が当たってできたかすり傷だ。","ENG":"It's for the wound I got when you threw your chain at me the last second.","TWN":"這是被你最後揮舞的鐵鍊劃破的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"다시 말해서…… 자네가 이겼다는 뜻이지.","JPN":"つまり……君は俺に勝ったのだよ。","ENG":"In other words... you won.","TWN":"換句話說……就是你贏了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어, 어어? 내가 이겼다고……?","JPN":"え、ええ？　俺が勝った……？","ENG":"W-what...? I won...?","TWN":"蛤？我贏了……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그래. 자네가 이겼어.","JPN":"そう。君の勝ちだ。","ENG":"Yes. You won.","TWN":"沒錯，你贏了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"후후, 역시 젊음은 부러워. 스펀지처럼 무엇이든 금방금방 체득해버리지.","JPN":"ふふ、やはり若さってのは羨ましい。スポンジのように、なんでもすぐ吸収してしまう。","ENG":"Hah hah. Oh, I envy youth. You soak up everything so fast.","TWN":"嘿嘿，年輕就是好啊。就像海綿一樣，什麼都能馬上領會。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"나에게도 자네 같은 시절이 있었는데 말이야.","JPN":"俺にも君のような時代があったのだがな。","ENG":"I used to be like you back in the day.","TWN":"我也有過像你這樣的時候。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그래도, 그래도…… 겨우 한 번만에 통과하다니…….","JPN":"それにしても……たった一度で合格するとは……","ENG":"But... but still... passing the test with just one attempt...","TWN":"但是，即使如此……你也是一次就通過了……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이렇게 야속한 기분이 드는 것도 오랜만이군.","JPN":"こんなに悔しいのは久しぶりだよ。","ENG":"It's been a long time since I felt so discouraged.","TWN":"好久沒有這麼歲月無情的感覺了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 지금의 나에게는 그런 야속함보다도 안도감이 앞서네.","JPN":"だが、今の俺はそれ以上にほっとしている。","ENG":"But right now, I feel more relieved than anything else.","TWN":"但對於現在的我來說，比起失落，更多的是覺得安心。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"잘해주었다. 애송이.","JPN":"よくやってくれた、小僧。","ENG":"Good job, kid.","TWN":"做得很好，小鬼。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네가…… 자네가 내 제자라서 정말 다행이야.","JPN":"君が……君が俺の弟子で本当によかった。","ENG":"I'm... glad to have you as my disciple.","TWN":"幸好……幸好你是我的徒弟。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"역시 자네는 내 자랑일세. 로이 버넷.","JPN":"やはり君は我が自慢だ。ロイ・バーネット。","ENG":"You are my pride and joy, Roy Burnett.","TWN":"你果然是我的驕傲，羅伊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐, 뭐야……?","JPN":"な、なんだよ……？","ENG":"W-what...?","TWN":"什，什麼啊……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"갑자기 오글거리게 무슨 짓이야? 뭐 잘못 먹었어?","JPN":"いきなりどうした？　変なものでも食べたのか？","ENG":"What's with all the compliments? What did they give you?","TWN":"突然這麼肉麻，你是不是吃錯什麼東西了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"버넷 경의 손자라고 너무 오냐오냐 가르치는 것 아닌가요, 새디어스 모건?","JPN":"バーネット卿の孫だからといって、甘やかしすぎではありませんの？　タデウス・モーガン。","ENG":"Don't you think you're pampering him too much because he's Sir Burnett's grandson, Thaddeus Morgan?","TWN":"不能因為他是伯內特卿的孫子，就太過放縱他，薩迪烏斯·摩根。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저는 물벼룩의 심사 결과를 인정하지 않았답니다.","JPN":"私はミジンコの審査結果を認めていませんわ。","ENG":"I still have not accepted Water Flea's test results.","TWN":"我不認同水蚤的審核結果。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 괜찮습니다. 이 녀석이 원하는 건 자리 같은 게 아니니까요.","JPN":"はは、大丈夫です。こいつが欲しいのは、役職ではありませんから。","ENG":"Hah hah, it's all right. He's not the type of kid who wants a title or something.","TWN":"哈哈，沒關係吧。這傢伙想要的並不是什麼地位。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"개인적으로는 이제 슬슬 로이 버넷을 믿어보는 것도 괜찮을 것 같습니다.","JPN":"俺個人としては、そろそろロイ・バーネットを信じてみるのもいいと思いますよ。","ENG":"However, I believe that we can start putting more trust in Roy Burnett.","TWN":"我個人認為，慢慢相信羅伊也不錯。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자, 버넷. 궁금한 게 있다고 했지. 그렇다면 기관장님께 직접 물어보도록.","JPN":"さて、バーネット。知りたいことがあると言っていたな？　では、機関長に直接聞いてみろ。","ENG":"All right, Burnett. You said you had questions. Go on and ask the chief directly.","TWN":"好了，伯內特，你有什麼疑問，可以直接詢問機關長。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네에게는 이제 그럴 권리가 있으니까.","JPN":"君にはもう、その権利があるのだから。","ENG":"You have the right to know now.","TWN":"你現在已經有這個權利了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"당장 꺼져 버려, 이 멍청한 녀석!","JPN":"とっとと消えろ、このアホ！","ENG":"Get outta here, you stupid boy!","TWN":"馬上給我滾出去，你這個愚蠢的傢伙！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"지금은 네가 기관에서 특별 대우를 받는 것 같지?","JPN":"今はお前が機関から特別扱いされていると思うだろう？","ENG":"You think you're getting some special treatment from the Institution?","TWN":"你現在是不是覺得在機關能享受特殊待遇？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"하지만 명심해! 너도 결국에는 할아버지처럼 평생을 기관에게 쥐어 짜이다가 버려질 거다!","JPN":"だが、肝に銘じておけ！　お前も結局は爺さんみたいに、一生機関にこき使われて捨てられるんだ！","ENG":"Mark my words! You'll end up exactly like your grandfather, and they will bleed you dry before throwing you away!","TWN":"但是記住了！你終究也會像爺爺一樣一輩子被機關榨乾，然後被拋棄！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"우리 할아버지…… 그리고 우리 아버지도 기관원이었다고 들었어.","JPN":"俺のお爺さん……そして、親父も機関員だったって聞いた。","ENG":"I heard that my grandfather... and my dad were also members of the Institution.","TWN":"我聽說我爺爺……還有我的爸爸，也都曾是機關成員。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래. 기관에게 있어, <color=#ffd34c>버넷</color>이 특별한 존재라는 건 대충 알겠어.","JPN":"そう。機関にとって、<color=#ffd34c>バーネット</color>が特別な存在だってことはだいたいわかった。","ENG":"Yeah. And I get that <color=#ffd34c>Burnetts</color> are special to the Institution.","TWN":"我大概明白，對機關來說，<color=#ffd34c>伯內特</color>這一姓氏是特別的存在。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 나는 할아버지나 아버지…… 그리고 버넷에 대해서도 몰라.","JPN":"でも俺はお爺さんや親父……そしてバーネットについて何も知らない。","ENG":"But I know nothing about my grandfather, my dad... or even the Burnetts as a matter of fact.","TWN":"但我對他們，我的爺爺，爸爸……以及伯內特卻一概不知。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까 알려줘, 홍차 폭탄.","JPN":"だから教えてくれ、紅茶爆弾。","ENG":"So tell me, Tea Bomb.","TWN":"所以告訴我吧，紅茶炸彈。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"기관에게 있어서 버넷은 대체 뭐지? 기관은 왜 나를 선택한 거야?","JPN":"機関にとってバーネットはいったい何だ？　機関はどうして俺を選んだ？","ENG":"What does the name Burnett mean to the Institution? And why me?","TWN":"對機關來說，伯內特到底是什麼？機關為什麼選擇我？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관이 왜 당신을 선택했냐는 말인가요?","JPN":"機関がどうしてあなたを選択したのかですって？","ENG":"Are you asking why the Institution chose you?","TWN":"你問我機關為什麼選擇你？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"흥, 물벼룩 주제에 모건에게 인정받았다고 자의식이 너무 비대해진 것 아닌가요?","JPN":"ふん、ミジンコのくせにモーガンから認められたからって、自身を過剰評価しているのでは？","ENG":"Hmph, perhaps Morgan's acknowledgment has inflated your ego, Water Flea.","TWN":"哼，區區水蚤，只不過是得到了摩根的認可，你的自我意識是不是太膨脹了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"착각하지 마세요. 기관이 당신을 선택한 게 아닙니다.","JPN":"勘違いしないでください。機関があなたを選択したわけではありません。","ENG":"Do not be mistaken. The Institution did not choose you.","TWN":"請不要誤會，不是機關選擇了你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"정확히 말하자면, 당신 외에 선택지가 없다고 해야겠죠.","JPN":"正確には、あなた以外の選択肢がなかったと言うべきでしょう。","ENG":"To be exact, we had no other choice but you.","TWN":"準確地說，應該是除了你別無選擇。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"선택지가 없다고?","JPN":"選択肢がない？","ENG":"No other choice?","TWN":"別無選擇？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"왜냐하면 그건 당신이 그런 운명을 타고났기 때문입니다.","JPN":"なぜなら、あなたがそういう運命を持って生まれたからです。","ENG":"That is because you were born with this fate.","TWN":"因為你天生就是這樣的命運。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"몹시 유감스럽게도, 이 세계에서 <color=#ffd34c>그걸</color> 쓸 수 있는 사람은 이제 <color=#ffd34c>두 사람</color>뿐이니까요.","JPN":"とても残念なことに、この世界で<color=#ffd34c>あれ</color>を使える人はもう<color=#ffd34c>二人</color>だけになってしまいましたから。","ENG":"And, unfortunately for us, there are only <color=#ffd34c>two people</color> in the world who now can use <color=#ffd34c>the thing</color>.","TWN":"有一個非常遺憾的事實是，在這個世界上能夠使用<color=#ffd34c>那件物品</color>的人現在只有<color=#ffd34c>二個人</color>。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그거? 두 사람? 무슨 뜻이야?","JPN":"あれ？　二人？　なんの話だ？","ENG":"Two people? What thing? What are you saying?","TWN":"那個？二個人？什麼意思？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"따라오세요.","JPN":"ついていらっしゃい。","ENG":"Follow me.","TWN":"跟我來。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신이 짊어지게 될 운명과 마주할 기회를 드리도록 하죠.","JPN":"あなたが背負うことになる運命と向き合うチャンスを与えましょう。","ENG":"I will give you the opportunity to face the fate you will have to bear.","TWN":"我會給你一個機會，讓你面對你即將背負的命運。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};